 1→import { type ReactNode, useCallback } from 'react';
 2→import { useListContext } from '../list_context';
 3→import './list_item.scss';
 4→
 5→export interface ListItemAccessory {
 6→  text?: string;
 7→  icon?: ReactNode;
 8→}
 9→
10→export interface ListItemProps {
11→  index: number;
12→  icon?: ReactNode;
13→  title: string;
14→  subtitle?: string;
15→  accessories?: ListItemAccessory[];
16→  onClick?: () => void;
17→}
18→
19→export function ListItem({
20→  index,
21→  icon,
22→  title,
23→  subtitle,
24→  accessories,
25→  onClick,
26→}: ListItemProps) {
27→  const { activeIndex, setActiveIndex } = useListContext();
28→  const isActive = activeIndex === index;
29→
30→  const handleMouseEnter = useCallback(() => {
31→    setActiveIndex(index);
32→  }, [
33→    index,
34→    setActiveIndex,
35→  ]);
36→
37→  return (
38→    <div
39→      id={`list-item-${index}`}
40→      className={`list-item${isActive ? ' list-item--active' : ''}`}
41→      data-list-index={index}
42→      role="option"
43→      aria-selected={isActive}
44→      onMouseEnter={handleMouseEnter}
45→      onClick={onClick}
46→    >
47→      <div className="list-item__left">
48→        {icon && <span className="list-item__icon">{icon}</span>}
49→        <span className="list-item__title">{title}</span>
50→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
51→      </div>
52→      {accessories && accessories.length > 0 && (
53→        <div className="list-item__accessories">
54→          {accessories.map((accessory, i) => (
55→            <span key={i} className="list-item__accessory">
56→              {accessory.icon}
57→              {accessory.text && (
58→                <span className="list-item__accessory-text">
59→                  {accessory.text}
60→                </span>
61→              )}
62→            </span>
63→          ))}
64→        </div>
65→      )}
66→    </div>
67→  );
68→}
